INSERT INTO UB_SURVEY_MENTEE (
    survey_number, mentee_school, mentee_grade, 
    mentee_hopeuni, mentee_hopemajor, subject_number
)
VALUES (
    #{surveyNumber}, #{menteeSchool}, #{menteeGrade}, 
    #{menteeHopeuni}, #{menteeHopemajor}, #{subjectNumber}
)

INSERT INTO UB_SURVEY_MENTOR (
    survey_number, grad_school, grad_depart, grad_score, subject_number
)
VALUES (
    #{surveyNumber}, #{gradSchool}, #{gradDepart}, #{gradScore}, #{subjectNumber}
)

